#https://leetcode.com/problems/valid-triangle-number/description/
from typing import List
class Solution:
    def triangleNumber(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        if n < 3:
            return 0
        result = 0
        for i in range (0, n-1):
            s1 = nums[i]
            #Two pointer section
            for j in range (i+1, n-1):
                for k in range (n-1, j, -1):
                    s2 = nums[j]
                    s3 = nums[k]
                    if (s1 + s2) > s3:
                        ##Insight: if the condition is true for position k, it is also true for positions between j and k
                        ##Cutting down loop time from 7373ms to 2974ms
                        result += (k-j)
                        break

        return result

s = Solution()
assert (s.triangleNumber([1,2,3])) == 0
assert (s.triangleNumber([2,2,3])) == 1
assert (s.triangleNumber([2,2,3,4])) == 3
assert (s.triangleNumber([4,2,3,4])) == 4
